"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[233],{8233:(e,i,a)=>{a.d(i,{default:()=>n});let n={en:{"socialt-arbete":{name:"Social work & inclusion",tagline:"Support people in vulnerable situations and contribute to a more inclusive society.",hero:{heading:"People first",sub:"As an ESC volunteer in social work, you work closely with people in difficult life situations — homelessness, addiction, mental health challenges, loneliness or social isolation. You become part of a team building dignity and trust, one relationship at a time."},stats:[{value:"6–12 mo",label:"Typical duration"},{value:"~30%",label:"Of all ESC placements"},{value:"€0",label:"Cost to you"}],body:"Social work is one of the largest categories within the European Solidarity Corps. It rarely demands any specific expertise — it demands presence. Cooking breakfast at a shelter. Accompanying someone to the bank. Talking, listening, being there.\n\nProjects exist all over Europe: from city-based shelters and supported housing in Berlin and Lisbon, to smaller local initiatives in rural areas. Many projects target specific groups — people experiencing homelessness, EU citizens in vulnerable situations, people with addiction issues, single parents, people leaving institutional care.\n\nYou usually get a concrete area of responsibility after an introductory period. The host organisation trains you on an ongoing basis, and you always work alongside experienced staff.",examples:[{icon:"\uD83C\uDFE0",title:"Shelters & supported housing",desc:"Help with daily routines, meals, community activities and creating a safe environment for residents."},{icon:"\uD83E\uDD32",title:"Outreach work",desc:"Join fieldwork to meet homeless people directly on the street — distribute food, clothes, hygiene items and information."},{icon:"☕",title:"Social meeting places",desc:"Run caf\xe9s, activity houses or day centres where people can come in from the cold and find community."},{icon:"\uD83E\uDDE0",title:"Mental health support",desc:"Be a support person in low-threshold services, group activities or individual guidance under supervision."},{icon:"\uD83C\uDF5E",title:"Food banks & distribution",desc:"Organise and distribute food to families in financial need — one of the most concrete forms of help."},{icon:"\uD83C\uDFAF",title:"Mentoring",desc:"Be a stable role model for young people or adults who need support in their reintegration or life change."}],skills:["Empathy & attentiveness","Conflict management","Active listening","Patience","Setting boundaries","Cross-cultural communication","Comfort with discomfort"],suitedFor:["You who want to work directly with people — not behind a screen.","You who are interested in social issues, equality or social work as a future career.","You who have the mental stability to encounter heavy stories without being broken by them.","You who are willing to learn — not to fix everything immediately."],practical:{duration:"Most projects are 6–12 months. Shorter projects (2–4 months) exist but are less common.",languages:"English usually suffices as a starting language. You are expected to learn the basics of the local language — without it, day-to-day work becomes difficult.",requirements:"No formal requirements, but personal stability is important. Some projects require a criminal record certificate. Previous volunteer experience is a plus but not necessary."}},"migration-integration":{name:"Migration & integration",tagline:"Help newcomers find their place in a new society — language, culture, rights, everyday life.",hero:{heading:"A bridge between worlds",sub:"As an ESC volunteer in migration and integration, you work alongside people who have just arrived in a new country — refugees, asylum seekers, unaccompanied minors, EU citizens in vulnerable situations. You help them navigate authorities, learn the language, find their new everyday life."},stats:[{value:"6–12 mo",label:"Typical duration"},{value:"25+",label:"Countries with active projects"},{value:"€0",label:"Cost to you"}],body:"Migration is one of Europe's biggest social questions — and one of the most meaningful areas to work in. ESC projects exist in reception centres, asylum housing, youth homes for unaccompanied minors, integration centres and organisations working with undocumented people.\n\nThe work is concrete and varied: language caf\xe9s, homework help for children, basic legal information, leisure activities, women's groups, rights awareness. Many projects are run by NGOs working alongside public systems, but also by churches, trade unions and municipal centres.\n\nProjects involving refugee reception often require specific supervision — you work with people who have sometimes experienced trauma, and the organisation provides ongoing support. You are not expected to be a therapist. You are expected to be a present human being.",examples:[{icon:"\uD83D\uDCAC",title:"Language caf\xe9s & lessons",desc:"Lead informal language gatherings where participants practise the local language through everyday conversation, games and themes."},{icon:"\uD83D\uDCCB",title:"Information on rights",desc:"Help people understand how to apply for residence permits, find housing, register with authorities."},{icon:"\uD83D\uDC68‍\uD83D\uDC69‍\uD83D\uDC67",title:"Family activities",desc:"Organise outings, cultural events and activities that build community between newcomers and the local community."},{icon:"\uD83D\uDCD6",title:"Homework support for children",desc:"Support children and young people with schoolwork, reading and learning the local language. Often in after-school programmes."},{icon:"\uD83C\uDF93",title:"Adult education",desc:"Assist in courses on computer skills, job seeking, driving theory or practical everyday knowledge."},{icon:"\uD83E\uDD1D",title:"Befriending programmes",desc:"Build one-on-one relationships between newcomers and local residents — one of the most effective integration measures."}],skills:["Cross-cultural competence","Patience with language barriers","Diplomacy","Teaching ability","Empathy","Ability to simplify complex information","Cultural humility"],suitedFor:["You who are curious about other cultures and want to become colleagues with people from around the world.","You who believe in a more open and solidaristic Europe.","You who can communicate even when language is insufficient.","You who can handle bureaucratic frustration without losing hope."],practical:{duration:"6–12 months. Some projects with long-term befriending or child support require at least 9 months.",languages:"English as a working language is common, but the local language is essential long-term. Some projects particularly value Arabic, Dari, Ukrainian or other languages.",requirements:"Mental stability is central. Some projects require an interview in advance. Experience working with people from different backgrounds is a plus."}},"utbildning-ungdom":{name:"Education & youth",tagline:"Inspire the next generation — in classrooms, youth centres, informal learning environments.",hero:{heading:"Light sparks in others",sub:"As an ESC volunteer in education and youth, you work with children, teenagers or young adults — in schools, youth centres, youth organisations or informal learning environments. You become a role model, a mentor, sometimes a big sister or brother."},stats:[{value:"6–12 mo",label:"Typical duration"},{value:"~25%",label:"Of all ESC placements"},{value:"€0",label:"Cost to you"}],body:"This is one of the broadest and most popular areas within the ESC. Projects range from regular schools (where you usually work as a language assistant or help in classrooms) to youth centres, youth organisations and groups working with informal learning — learning that happens outside school, through activities, games, workshops and conversations.\n\nMany European schools host ESC volunteers to give pupils authentic contact with another European language and culture. You are not a teacher — you are a present young adult introducing English, Swedish or your own culture, often through conversation and play.\n\nThe youth sector is just as important. It's about being a stable presence for young people who may not always have that support at home — leading activities, listening, organising outings, building mentorship over time.",examples:[{icon:"\uD83C\uDFEB",title:"School language assistant",desc:"Support language teachers in classrooms, lead smaller groups, help students who need extra support. Often in EU languages or English."},{icon:"\uD83C\uDFAE",title:"Youth centres & clubs",desc:"Lead activities, games, workshops and conversations with teenagers. Build lasting mentorships over time."},{icon:"\uD83C\uDFA8",title:"Creative workshops",desc:"Run art, music, drama or craft workshops as tools for personal development and expression."},{icon:"\uD83D\uDCD6",title:"Homework support",desc:"Support children and young people who need extra help with schoolwork, often combined with after-school activities."},{icon:"\uD83C\uDF10",title:"International exchanges",desc:"Help organise Erasmus+ exchanges, youth conferences and European awareness campaigns."},{icon:"⚽",title:"Sport & outdoor activities",desc:"Lead sports and outdoor activities as tools for inclusion, health and teamwork."}],skills:["Pedagogical sensitivity","Energy & playfulness","Group leadership","Conflict resolution among children/youth","Creative problem-solving","Patience","Ability to be a role model"],suitedFor:["You who enjoy children and young people and find it easy to communicate with them.","You who are considering a future as a teacher, youth worker, social worker or child psychologist.","You who have energy and ideas — and can handle chaos when needed.","You who want to discover your own society through younger eyes."],practical:{duration:"9–12 months is most common, often tied to school years. Summer projects (2–3 months) exist but mainly for camps and leisure activities.",languages:"English is enough in many language assistant roles. For youth work you usually need to learn the local language — that is how you build relationships.",requirements:"Many schools require a criminal record certificate. Experience working with children (summer camps, scouts, sports coaching) is a plus."}},"miljo-hallbarhet":{name:"Environment & sustainability",tagline:"Work concretely on climate, biodiversity, organic farming and sustainable communities.",hero:{heading:"For a planet that holds",sub:"As an ESC volunteer in environment and sustainability, you work on climate issues, nature conservation, organic farming or circular economy. You become part of Europe's green transition — in nature reserves, on organic farms, in environmental organisations or in cities running sustainability projects."},stats:[{value:"3–12 mo",label:"Wide range of durations"},{value:"Rural",label:"Many projects outside cities"},{value:"€0",label:"Cost to you"}],body:"This area has grown significantly in recent years. ESC projects exist in nature conservation (forest management, wetland restoration, bird monitoring), organic farming (farms hosting WWOOF-style volunteers), environmental education (centres hosting school classes), climate activism (NGOs and advocacy organisations) and sustainable urban development.\n\nMany projects are based in rural areas, sometimes in remote regions — something to be aware of. It means close contact with nature, but also that you may be quite isolated from larger cities and nightlife. Those seeking authentic rural experience will feel at home; those wanting urban energy should look for city-based projects.\n\nThe work is often physical — you plant, dig, prune, observe, document. You learn new techniques and gain practical knowledge you can take with you.",examples:[{icon:"\uD83C\uDF33",title:"Forest & nature conservation",desc:"Planting, clearing, biotope restoration, bird surveys, monitoring of protected species."},{icon:"\uD83C\uDF3E",title:"Organic farming",desc:"Learn permaculture, agroecology and sustainable farming through practical work on farms and gardens."},{icon:"\uD83D\uDC1D",title:"Biodiversity",desc:"Support projects on bees, butterflies, small birds — surveys, habitat creation, public events."},{icon:"\uD83D\uDCE2",title:"Environmental education",desc:"Lead educational activities for school classes and the public at nature centres or outdoor schools."},{icon:"♻️",title:"Circular economy",desc:"Work with reuse projects, repair caf\xe9s, second-hand shops and initiatives to reduce food waste."},{icon:"\uD83C\uDF0D",title:"Climate activism",desc:"Support organisations pursuing climate issues through campaigns, advocacy and community dialogue."}],skills:["Practical problem-solving","Physical endurance","Basic scientific knowledge","Patience (nature work takes time)","Outdoor teamwork","Long-term thinking","Adaptability"],suitedFor:["You who enjoy being outdoors and are not afraid of physical work or bad weather.","You who want to translate climate commitment into concrete action.","You who are considering a future in environment, biology, agronomy or sustainability.","You who can enjoy the silence and rhythm of a rural environment."],practical:{duration:"Wide variation. Short seasonal projects (2–3 months during harvest or planting) exist alongside year-long projects. Think about season when applying.",languages:"English is enough in many international environmental projects. On smaller organic farms, basic local language can be more important.",requirements:"No formal requirements. But physical ability, a driving licence (sometimes) and stability in rural settings are pluses. Consider allergies (bees, hay, sun)."}},"kultur-konst":{name:"Culture & arts",tagline:"Use creativity as a tool for change — art, media, theatre, film, cultural heritage.",hero:{heading:"Creativity that changes things",sub:"As an ESC volunteer in culture and arts, you work at museums, cultural centres, film festivals, theatres, media organisations or community-based art projects. You help culture reach more people — and gain professional experience in an industry that can otherwise be hard to enter."},stats:[{value:"6–12 mo",label:"Typical duration"},{value:"Cities",label:"Mainly urban projects"},{value:"€0",label:"Cost to you"}],body:"The cultural area within ESC is broad and varied. It includes both traditional institutional culture — museums, galleries, theatres, film festivals, heritage — and more activist, community-based forms: street art, community theatre, video as a tool for marginalised voices, documentary projects with refugees, craft collectives.\n\nFor many trying to enter the cultural sector, ESC is an excellent springboard. You get real work experience at a museum, a cultural editorial team or in a film production — something that otherwise requires internships that are often unpaid or tied to studies.\n\nIt's worth noting that these placements are often popular, so competition can be tough. Early application and a clear motivation about why specifically culture is helpful.",examples:[{icon:"\uD83C\uDFDB️",title:"Museums & galleries",desc:"Support audience work, exhibition production, educational activities, communication and events."},{icon:"\uD83C\uDFAC",title:"Film & media",desc:"Help at film festivals, documentary projects, youth film schools or community media producers."},{icon:"\uD83C\uDFAD",title:"Theatre & performing arts",desc:"Assist in productions, youth theatre groups, community theatre or street theatre in marginalised areas."},{icon:"\uD83C\uDFB5",title:"Music & music education",desc:"Support music schools, choir projects, concert arrangements or music therapy initiatives."},{icon:"\uD83D\uDCDA",title:"Libraries & literature",desc:"Run reading promotion, author visits, creative writing for young people or storytelling workshops."},{icon:"\uD83D\uDEE0️",title:"Crafts & traditions",desc:"Learn and help convey local traditions — ceramics, woodwork, weaving, food — at heritage centres."}],skills:["Creative thinking","Visual communication","Project management","Storytelling","Social media literacy","Artistic discipline","Cross-cultural aesthetic awareness"],suitedFor:["You who have artistic interest, academic or practical.","You who are considering a future in art, film, theatre, media, museums or cultural policy.","You who want to build a portfolio and network in an industry that is otherwise hard to access.","You who see culture as a tool for change, not just entertainment."],practical:{duration:"6–12 months is most common, sometimes synced with cultural seasons. Festival projects can be shorter and more intensive.",languages:"English is often enough in international contexts (museums, festivals), but for community work the local language is key.",requirements:"Artistic experience is a plus but not always necessary. Many projects want to see motivation and a creative portfolio (even basic)."}},"halsa-omsorg":{name:"Health & care",tagline:"Contribute to wellbeing — public health, elderly care, disability support, palliative care.",hero:{heading:"Presence that heals",sub:"As an ESC volunteer in health and care, you work with elderly people, people with disabilities, people in palliative care or public health-oriented organisations. You are not medical staff — you are a human presence that complements and relieves professionals."},stats:[{value:"6–12 mo",label:"Typical duration"},{value:"EU + 3rd",label:"Inside and outside EU"},{value:"€0",label:"Cost to you"}],body:"Health and care is an area where your presence matters a lot — perhaps more than you think. It is often not about medical interventions but about companionship. Reading aloud to an elderly woman. Being a swimming buddy for a man with intellectual disability. Holding the hand of someone whose life is drawing to a close.\n\nProjects exist in care homes, day activities for people with disabilities, hospices, low-threshold clinics for vulnerable groups, organisations working on public health or HIV prevention. Some specifically work with younger people with mental health challenges.\n\nIt is an area that requires mental stability. You sometimes encounter illness, ageing and death. The host organisation provides supervision and support, and you never work alone in heavy situations. But it is important to reflect honestly on whether you have the resources for it.",examples:[{icon:"\uD83D\uDC75",title:"Elderly care",desc:"Companionship, reading aloud, walks, community activities at care homes or with isolated older people."},{icon:"♿",title:"Disability support",desc:"Assist in day activities, accompany on outings, be a swimming buddy or fellow participant in leisure activities."},{icon:"\uD83D\uDD4A️",title:"Palliative care & hospice",desc:"Be a quiet presence for people at the end of life. Substantial supervision and support included."},{icon:"\uD83C\uDFE5",title:"Low-threshold clinics",desc:"Help at clinics working with homeless people, people with addiction or undocumented people on health matters."},{icon:"\uD83D\uDCE2",title:"Public health work",desc:"Inform on sexual health, mental health, addiction or vaccination — often in schools or at events."},{icon:"\uD83E\uDDE0",title:"Youth mental health",desc:"Support organisations working with young people suffering from anxiety, depression or social isolation."}],skills:["Mental stability","Empathy without absorbing","Concrete care","Ability to sit in silence","Hygiene awareness","Discretion","Calm under pressure"],suitedFor:["You who are considering a future in healthcare, social care, psychology or public health.","You who have mental stability and self-awareness.","You who are not afraid of the physical, the fragile, the human.","You who want to meet life in its full breadth — including ageing and endings."],practical:{duration:"6–12 months. Some palliative projects require at least 9 months to build continuity with patients.",languages:"Local language is often essential — relationships are built in conversation. English rarely takes you far in daily care.",requirements:"Mental stability and self-reflection are important. Criminal record certificate often required. Experience caring for close family members is a plus."}}},es:{"socialt-arbete":{name:"Trabajo social e inclusi\xf3n",tagline:"Apoya a personas en situaciones vulnerables y contribuye a una sociedad m\xe1s inclusiva.",hero:{heading:"Las personas primero",sub:"Como voluntario del CES en trabajo social, trabajas estrechamente con personas en situaciones de vida dif\xedciles: sin hogar, adicciones, problemas de salud mental, soledad o aislamiento social. Te conviertes en parte de un equipo que construye dignidad y confianza, una relaci\xf3n a la vez."},stats:[{value:"6–12 meses",label:"Duraci\xf3n t\xedpica"},{value:"~30%",label:"De todas las plazas CES"},{value:"0 €",label:"Coste para ti"}],body:'El trabajo social es una de las categor\xedas m\xe1s grandes del Cuerpo Europeo de Solidaridad. Rara vez exige una "experiencia" espec\xedfica: exige presencia. Preparar el desayuno en un albergue. Acompa\xf1ar a alguien al banco. Hablar, escuchar, estar ah\xed.\n\nLos proyectos existen por toda Europa: desde albergues urbanos y viviendas tuteladas en Berl\xedn y Lisboa, hasta iniciativas locales m\xe1s peque\xf1as en zonas rurales. Muchos proyectos se dirigen a grupos espec\xedficos: personas sin hogar, ciudadanos de la UE en situaci\xf3n vulnerable, personas con problemas de adicci\xf3n, familias monoparentales, personas que dejan instituciones.\n\nNormalmente recibes una responsabilidad concreta tras un per\xedodo de iniciaci\xf3n. La organizaci\xf3n de acogida te forma de manera continua y siempre trabajas junto a personal experimentado.',examples:[{icon:"\uD83C\uDFE0",title:"Albergues y viviendas tuteladas",desc:"Ayuda con las rutinas diarias, las comidas, las actividades comunitarias y a crear un entorno seguro para los residentes."},{icon:"\uD83E\uDD32",title:"Trabajo de calle",desc:"Acompa\xf1a salidas de campo para encontrarte con personas sin hogar directamente en la calle: reparte comida, ropa, productos de higiene e informaci\xf3n."},{icon:"☕",title:"Espacios sociales",desc:"Gestiona caf\xe9s sociales, casas de actividades o centros de d\xeda donde las personas puedan refugiarse del fr\xedo y encontrar comunidad."},{icon:"\uD83E\uDDE0",title:"Apoyo en salud mental",desc:"S\xe9 persona de apoyo en servicios de baja exigencia, actividades grupales o acompa\xf1amiento individual bajo supervisi\xf3n."},{icon:"\uD83C\uDF5E",title:"Bancos de alimentos",desc:"Organiza y reparte alimentos a familias en dificultad econ\xf3mica: una de las formas m\xe1s concretas de ayuda."},{icon:"\uD83C\uDFAF",title:"Mentor\xeda",desc:"S\xe9 una figura estable para j\xf3venes o adultos que necesitan apoyo en su reintegraci\xf3n o un cambio de vida."}],skills:["Empat\xeda y escucha","Gesti\xf3n de conflictos","Escucha activa","Paciencia","Saber poner l\xedmites","Comunicaci\xf3n intercultural","Capacidad de estar en lo inc\xf3modo"],suitedFor:["T\xfa que quieres trabajar directamente con personas, no detr\xe1s de una pantalla.","T\xfa que te interesan los temas sociales, la igualdad o el trabajo social como profesi\xf3n futura.","T\xfa que tienes la estabilidad mental para escuchar historias duras sin romperte.","T\xfa que est\xe1s dispuesto a aprender, no a arreglarlo todo de inmediato."],practical:{duration:"La mayor\xeda de los proyectos son de 6–12 meses. Los proyectos cortos (2–4 meses) existen pero son menos habituales.",languages:"El ingl\xe9s suele bastar como idioma inicial. Se espera que aprendas lo b\xe1sico del idioma local: sin \xe9l, el trabajo diario se complica.",requirements:"No hay requisitos formales, pero la estabilidad personal es importante. Algunos proyectos requieren un certificado de antecedentes penales. La experiencia previa en voluntariado es valorada, pero no necesaria."}},"migration-integration":{name:"Migraci\xf3n e integraci\xf3n",tagline:"Ayuda a los reci\xe9n llegados a encontrar su lugar en una nueva sociedad: idioma, cultura, derechos, vida cotidiana.",hero:{heading:"Un puente entre mundos",sub:"Como voluntario del CES en migraci\xf3n e integraci\xf3n, trabajas junto a personas que acaban de llegar a un nuevo pa\xeds: refugiados, solicitantes de asilo, menores no acompa\xf1ados, ciudadanos de la UE en situaci\xf3n vulnerable. Les ayudas a moverse entre administraciones, aprender el idioma, encontrar su nueva vida cotidiana."},stats:[{value:"6–12 meses",label:"Duraci\xf3n t\xedpica"},{value:"25+",label:"Pa\xedses con proyectos activos"},{value:"0 €",label:"Coste para ti"}],body:"La migraci\xf3n es una de las grandes cuestiones sociales de Europa y una de las \xe1reas m\xe1s significativas para trabajar. Los proyectos CES existen en centros de acogida, viviendas de asilo, hogares para menores no acompa\xf1ados, centros de integraci\xf3n y organizaciones que trabajan con personas sin papeles.\n\nEl trabajo es concreto y variado: caf\xe9s ling\xfc\xedsticos, apoyo a deberes para ni\xf1os, informaci\xf3n jur\xeddica b\xe1sica, actividades de ocio, grupos de mujeres, talleres sobre derechos. Muchos proyectos los gestionan ONG que trabajan en paralelo al sistema p\xfablico, pero tambi\xe9n iglesias, sindicatos y centros municipales.\n\nLos proyectos que implican acogida de refugiados a menudo requieren supervisi\xf3n espec\xedfica: trabajas con personas que a veces han vivido traumas, y la organizaci\xf3n te ofrece apoyo continuo. No se espera que seas terapeuta. Se espera que seas un ser humano presente.",examples:[{icon:"\uD83D\uDCAC",title:"Caf\xe9s ling\xfc\xedsticos y clases",desc:"Dirige encuentros ling\xfc\xedsticos informales donde los participantes practican el idioma local a trav\xe9s de conversaciones cotidianas, juegos y temas."},{icon:"\uD83D\uDCCB",title:"Informaci\xf3n sobre derechos",desc:"Ayuda a las personas a entender c\xf3mo solicitar permisos de residencia, encontrar vivienda, registrarse en las administraciones."},{icon:"\uD83D\uDC68‍\uD83D\uDC69‍\uD83D\uDC67",title:"Actividades familiares",desc:"Organiza salidas, eventos culturales y actividades que construyen comunidad entre reci\xe9n llegados y la poblaci\xf3n local."},{icon:"\uD83D\uDCD6",title:"Apoyo escolar para ni\xf1os",desc:"Apoya a ni\xf1os y j\xf3venes con los deberes, la lectura y el aprendizaje del idioma local. A menudo en actividades extraescolares."},{icon:"\uD83C\uDF93",title:"Educaci\xf3n para adultos",desc:"Ayuda en cursos de inform\xe1tica, b\xfasqueda de empleo, teor\xeda del carn\xe9 de conducir o conocimientos pr\xe1cticos cotidianos."},{icon:"\uD83E\uDD1D",title:"Programas de mentor\xeda",desc:"Construye relaciones uno a uno entre reci\xe9n llegados y residentes locales: una de las medidas de integraci\xf3n m\xe1s eficaces."}],skills:["Competencia intercultural","Paciencia con las barreras idiom\xe1ticas","Diplomacia","Capacidad pedag\xf3gica","Empat\xeda","Capacidad de simplificar informaci\xf3n compleja","Humildad cultural"],suitedFor:["T\xfa que sientes curiosidad por otras culturas y quieres compartir trabajo con personas de todo el mundo.","T\xfa que crees en una Europa m\xe1s abierta y solidaria.","T\xfa que sabes comunicarte incluso cuando el idioma no alcanza.","T\xfa que sabes manejar la frustraci\xf3n burocr\xe1tica sin perder la esperanza."],practical:{duration:"6–12 meses. Algunos proyectos de mentor\xeda a largo plazo o apoyo a ni\xf1os requieren al menos 9 meses.",languages:"El ingl\xe9s como lengua de trabajo es com\xfan, pero el idioma local es esencial a largo plazo. Algunos proyectos valoran especialmente el \xe1rabe, dari, ucraniano u otras lenguas.",requirements:"La estabilidad mental es central. Algunos proyectos requieren una entrevista previa. La experiencia trabajando con personas de or\xedgenes diversos es valorada."}},"utbildning-ungdom":{name:"Educaci\xf3n y juventud",tagline:"Inspira a la pr\xf3xima generaci\xf3n: en aulas, centros juveniles y entornos de aprendizaje informal.",hero:{heading:"Enciende chispas en otros",sub:"Como voluntario del CES en educaci\xf3n y juventud, trabajas con ni\xf1os, adolescentes o j\xf3venes adultos: en escuelas, centros juveniles, organizaciones de juventud o entornos de aprendizaje informal. Te conviertes en un modelo, un mentor, a veces un hermano o hermana mayor."},stats:[{value:"6–12 meses",label:"Duraci\xf3n t\xedpica"},{value:"~25%",label:"De todas las plazas CES"},{value:"0 €",label:"Coste para ti"}],body:"Esta es una de las \xe1reas m\xe1s amplias y populares del CES. Los proyectos van desde escuelas regulares (donde normalmente eres asistente de idiomas o ayudas en el aula) hasta centros juveniles, organizaciones de j\xf3venes y grupos que trabajan con aprendizaje informal: aprendizaje que sucede fuera de la escuela, a trav\xe9s de actividades, juegos, talleres y conversaciones.\n\nMuchas escuelas europeas acogen voluntarios CES para dar a los alumnos contacto aut\xe9ntico con otro idioma y otra cultura europea. No eres profesor: eres un adulto joven presente que introduce el ingl\xe9s, el sueco o tu propia cultura, a menudo a trav\xe9s de la conversaci\xf3n y el juego.\n\nEl sector juvenil es igual de importante. Se trata de ser una presencia estable para j\xf3venes que quiz\xe1s no siempre tienen ese apoyo en casa: dirigir actividades, escuchar, organizar salidas, construir mentor\xeda con el tiempo.",examples:[{icon:"\uD83C\uDFEB",title:"Asistente de idiomas en escuelas",desc:"Apoya a profesores de idiomas en el aula, dirige grupos peque\xf1os, ayuda a alumnos que necesitan apoyo extra. A menudo en lenguas de la UE o ingl\xe9s."},{icon:"\uD83C\uDFAE",title:"Centros y clubes juveniles",desc:"Dirige actividades, juegos, talleres y conversaciones con adolescentes. Construye mentor\xedas duraderas con el tiempo."},{icon:"\uD83C\uDFA8",title:"Talleres creativos",desc:"Gestiona talleres de arte, m\xfasica, teatro o artesan\xeda como herramientas de desarrollo personal y expresi\xf3n."},{icon:"\uD83D\uDCD6",title:"Apoyo escolar",desc:"Apoya a ni\xf1os y j\xf3venes que necesitan ayuda extra con los deberes, a menudo combinado con actividades de ocio."},{icon:"\uD83C\uDF10",title:"Intercambios internacionales",desc:"Ayuda a organizar intercambios Erasmus+, conferencias juveniles y campa\xf1as de conciencia europea."},{icon:"⚽",title:"Deporte y actividades al aire libre",desc:"Dirige actividades deportivas y al aire libre como herramientas de inclusi\xf3n, salud y trabajo en equipo."}],skills:["Sensibilidad pedag\xf3gica","Energ\xeda y juego","Liderazgo grupal","Resoluci\xf3n de conflictos entre ni\xf1os/j\xf3venes","Resoluci\xf3n creativa de problemas","Paciencia","Capacidad de ser modelo"],suitedFor:["T\xfa que disfrutas con ni\xf1os y j\xf3venes y te resulta f\xe1cil comunicarte con ellos.","T\xfa que est\xe1s considerando un futuro como docente, educador social, trabajador social o psic\xf3logo infantil.","T\xfa que tienes energ\xeda e ideas, y aguantas el caos cuando hace falta.","T\xfa que quieres descubrir tu propia sociedad a trav\xe9s de ojos m\xe1s j\xf3venes."],practical:{duration:"9–12 meses es lo m\xe1s habitual, a menudo ligado al a\xf1o escolar. Los proyectos de verano (2–3 meses) existen pero principalmente en campamentos y actividades de ocio.",languages:"El ingl\xe9s basta en muchos puestos de asistente de idiomas. Para el trabajo juvenil normalmente necesitas aprender el idioma local: as\xed se construyen las relaciones.",requirements:"Muchas escuelas exigen certificado de antecedentes penales. La experiencia con ni\xf1os (campamentos, scouts, entrenadores deportivos) es valorada."}},"miljo-hallbarhet":{name:"Medio ambiente y sostenibilidad",tagline:"Trabaja concretamente en clima, biodiversidad, agricultura ecol\xf3gica y comunidades sostenibles.",hero:{heading:"Por un planeta que aguante",sub:"Como voluntario del CES en medio ambiente y sostenibilidad, trabajas en cuestiones clim\xe1ticas, conservaci\xf3n de la naturaleza, agricultura ecol\xf3gica o econom\xeda circular. Te conviertes en parte de la transici\xf3n verde europea: en reservas naturales, en granjas ecol\xf3gicas, en organizaciones ambientales o en ciudades que impulsan proyectos sostenibles."},stats:[{value:"3–12 meses",label:"Amplia variaci\xf3n"},{value:"Rural",label:"Muchos proyectos fuera de ciudades"},{value:"0 €",label:"Coste para ti"}],body:"Esta \xe1rea ha crecido mucho en los \xfaltimos a\xf1os. Los proyectos CES existen en conservaci\xf3n de la naturaleza (gesti\xf3n forestal, restauraci\xf3n de humedales, monitoreo de aves), agricultura ecol\xf3gica (granjas que acogen voluntarios estilo WWOOF), educaci\xf3n ambiental (centros que reciben clases escolares), activismo clim\xe1tico (ONG y organizaciones de incidencia) y desarrollo urbano sostenible.\n\nMuchos proyectos est\xe1n en zonas rurales, a veces en regiones remotas: es algo a tener en cuenta. Significa contacto cercano con la naturaleza, pero tambi\xe9n que puedes estar bastante aislado de ciudades grandes y vida nocturna. Quien busca experiencia rural aut\xe9ntica se sentir\xe1 como en casa; quien quiere ambiente urbano debe buscar proyectos en ciudades.\n\nEl trabajo a menudo es f\xedsico: plantas, cavas, podas, observas, documentas. Aprendes t\xe9cnicas nuevas y obtienes conocimientos pr\xe1cticos que te llevas contigo.",examples:[{icon:"\uD83C\uDF33",title:"Conservaci\xf3n forestal y natural",desc:"Plantaci\xf3n, desbroce, restauraci\xf3n de biotopos, censos de aves, seguimiento de especies protegidas."},{icon:"\uD83C\uDF3E",title:"Agricultura ecol\xf3gica",desc:"Aprende permacultura, agroecolog\xeda y agricultura sostenible mediante trabajo pr\xe1ctico en granjas y huertos."},{icon:"\uD83D\uDC1D",title:"Biodiversidad",desc:"Apoya proyectos sobre abejas, mariposas, p\xe1jaros peque\xf1os: censos, creaci\xf3n de h\xe1bitats, eventos p\xfablicos."},{icon:"\uD83D\uDCE2",title:"Educaci\xf3n ambiental",desc:"Dirige actividades pedag\xf3gicas para clases escolares y p\xfablico en centros de naturaleza o escuelas al aire libre."},{icon:"♻️",title:"Econom\xeda circular",desc:"Trabaja con proyectos de reutilizaci\xf3n, repair caf\xe9s, tiendas de segunda mano e iniciativas contra el desperdicio alimentario."},{icon:"\uD83C\uDF0D",title:"Activismo clim\xe1tico",desc:"Apoya organizaciones que defienden cuestiones clim\xe1ticas mediante campa\xf1as, incidencia y di\xe1logo comunitario."}],skills:["Resoluci\xf3n pr\xe1ctica de problemas","Resistencia f\xedsica","Conocimientos cient\xedficos b\xe1sicos","Paciencia (el trabajo en la naturaleza es lento)","Trabajo en equipo al aire libre","Pensamiento a largo plazo","Capacidad de adaptaci\xf3n"],suitedFor:["T\xfa que disfrutas del aire libre y no temes el trabajo f\xedsico ni el mal tiempo.","T\xfa que quieres traducir el compromiso clim\xe1tico en acci\xf3n concreta.","T\xfa que est\xe1s considerando un futuro en medio ambiente, biolog\xeda, agronom\xeda o sostenibilidad.","T\xfa que puedes disfrutar del silencio y el ritmo de un entorno rural."],practical:{duration:"Gran variaci\xf3n. Existen proyectos estacionales cortos (2–3 meses durante cosechas o plantaciones) junto a proyectos anuales. Piensa en la estaci\xf3n al solicitar.",languages:"El ingl\xe9s basta en muchos proyectos ambientales internacionales. En granjas ecol\xf3gicas peque\xf1as, el idioma local b\xe1sico puede ser m\xe1s importante.",requirements:"No hay requisitos formales. Pero la capacidad f\xedsica, el carn\xe9 de conducir (a veces) y la estabilidad en entornos rurales son valorados. Considera alergias (abejas, heno, sol)."}},"kultur-konst":{name:"Cultura y arte",tagline:"Usa la creatividad como herramienta de cambio: arte, medios, teatro, cine, patrimonio cultural.",hero:{heading:"Creatividad que cambia las cosas",sub:"Como voluntario del CES en cultura y arte, trabajas en museos, centros culturales, festivales de cine, teatros, organizaciones de medios o proyectos art\xedsticos comunitarios. Ayudas a que la cultura llegue a m\xe1s personas, y obtienes experiencia profesional en un sector al que de otro modo es dif\xedcil entrar."},stats:[{value:"6–12 meses",label:"Duraci\xf3n t\xedpica"},{value:"Ciudades",label:"Mayor\xeda de proyectos urbanos"},{value:"0 €",label:"Coste para ti"}],body:"El \xe1rea cultural dentro del CES es amplia y variada. Incluye tanto la cultura institucional tradicional (museos, galer\xedas, teatros, festivales de cine, patrimonio) como formas m\xe1s activistas y comunitarias: arte urbano, teatro comunitario, v\xeddeo como herramienta para voces marginadas, proyectos documentales con refugiados, colectivos artesanales.\n\nPara muchos que quieren entrar en el sector cultural, el CES es un excelente trampol\xedn. Obtienes experiencia laboral real en un museo, una redacci\xf3n cultural o una producci\xf3n cinematogr\xe1fica: algo que de otro modo requiere pr\xe1cticas a menudo no remuneradas o vinculadas a los estudios.\n\nVale la pena se\xf1alar que estas plazas suelen ser populares, as\xed que la competencia puede ser dura. Solicitar pronto y tener una motivaci\xf3n clara sobre por qu\xe9 la cultura espec\xedficamente es \xfatil.",examples:[{icon:"\uD83C\uDFDB️",title:"Museos y galer\xedas",desc:"Apoya el trabajo con p\xfablicos, la producci\xf3n de exposiciones, las actividades pedag\xf3gicas, la comunicaci\xf3n y los eventos."},{icon:"\uD83C\uDFAC",title:"Cine y medios",desc:"Ayuda en festivales de cine, proyectos documentales, escuelas de cine juveniles o productoras de medios comunitarios."},{icon:"\uD83C\uDFAD",title:"Teatro y artes esc\xe9nicas",desc:"Asiste en producciones, grupos de teatro juvenil, teatro comunitario o teatro de calle en zonas marginadas."},{icon:"\uD83C\uDFB5",title:"M\xfasica y educaci\xf3n musical",desc:"Apoya escuelas de m\xfasica, proyectos corales, organizaci\xf3n de conciertos o iniciativas de musicoterapia."},{icon:"\uD83D\uDCDA",title:"Bibliotecas y literatura",desc:"Impulsa la promoci\xf3n de la lectura, visitas de autores, escritura creativa para j\xf3venes o talleres de narraci\xf3n."},{icon:"\uD83D\uDEE0️",title:"Artesan\xeda y tradiciones",desc:"Aprende y ayuda a transmitir tradiciones locales: cer\xe1mica, carpinter\xeda, tejido, gastronom\xeda, en centros patrimoniales."}],skills:["Pensamiento creativo","Comunicaci\xf3n visual","Gesti\xf3n de proyectos","Narrativa","Competencia en redes sociales","Disciplina art\xedstica","Sensibilidad est\xe9tica intercultural"],suitedFor:["T\xfa que tienes inter\xe9s art\xedstico, acad\xe9mico o pr\xe1ctico.","T\xfa que est\xe1s considerando un futuro en arte, cine, teatro, medios, museos o pol\xedtica cultural.","T\xfa que quieres construir portafolio y red en un sector dif\xedcil de acceder.","T\xfa que ves la cultura como herramienta de cambio, no solo entretenimiento."],practical:{duration:"6–12 meses es lo m\xe1s habitual, a veces sincronizado con las temporadas culturales. Los proyectos de festivales pueden ser m\xe1s cortos e intensos.",languages:"El ingl\xe9s suele bastar en contextos internacionales (museos, festivales), pero para el trabajo comunitario el idioma local es clave.",requirements:"La experiencia art\xedstica es valorada pero no siempre necesaria. Muchos proyectos quieren ver motivaci\xf3n y un portafolio creativo (aunque sea b\xe1sico)."}},"halsa-omsorg":{name:"Salud y cuidado",tagline:"Contribuye al bienestar: salud p\xfablica, cuidado de mayores, apoyo a discapacidad, cuidados paliativos.",hero:{heading:"Una presencia que sana",sub:"Como voluntario del CES en salud y cuidado, trabajas con personas mayores, personas con discapacidad, personas en cuidados paliativos u organizaciones orientadas a la salud p\xfablica. No eres personal sanitario: eres una presencia humana que complementa y alivia a los profesionales."},stats:[{value:"6–12 meses",label:"Duraci\xf3n t\xedpica"},{value:"UE + 3\xaa",label:"Dentro y fuera de la UE"},{value:"0 €",label:"Coste para ti"}],body:"Salud y cuidado es un \xe1rea donde tu presencia importa mucho, quiz\xe1s m\xe1s de lo que crees. A menudo no se trata de intervenciones m\xe9dicas, sino de compa\xf1\xeda. Leer en voz alta a una mujer mayor. Ser compa\xf1ero de nataci\xf3n de un hombre con discapacidad intelectual. Sostener la mano de alguien cuya vida se acerca a su fin.\n\nLos proyectos existen en residencias, actividades de d\xeda para personas con discapacidad, hospicios, consultas de baja exigencia para grupos vulnerables, organizaciones que trabajan en salud p\xfablica o prevenci\xf3n del VIH. Algunos trabajan espec\xedficamente con j\xf3venes con problemas de salud mental.\n\nEs un \xe1rea que exige estabilidad mental. A veces te encuentras con enfermedad, envejecimiento y muerte. La organizaci\xf3n de acogida te ofrece supervisi\xf3n y apoyo, y nunca trabajas solo en situaciones duras. Pero es importante reflexionar honestamente sobre si tienes los recursos para ello.",examples:[{icon:"\uD83D\uDC75",title:"Cuidado de mayores",desc:"Compa\xf1\xeda, lecturas en voz alta, paseos, actividades comunitarias en residencias o con personas mayores aisladas."},{icon:"♿",title:"Apoyo a la discapacidad",desc:"Asiste en actividades de d\xeda, acompa\xf1a en salidas, s\xe9 compa\xf1ero de nataci\xf3n o de actividades de ocio."},{icon:"\uD83D\uDD4A️",title:"Cuidados paliativos y hospicios",desc:"S\xe9 una presencia tranquila para personas al final de la vida. Incluye supervisi\xf3n y apoyo sustanciales."},{icon:"\uD83C\uDFE5",title:"Consultas de baja exigencia",desc:"Ayuda en consultas que trabajan con personas sin hogar, personas con adicciones o personas sin papeles en cuestiones de salud."},{icon:"\uD83D\uDCE2",title:"Trabajo de salud p\xfablica",desc:"Informa sobre salud sexual, salud mental, adicciones o vacunaci\xf3n: a menudo en escuelas o eventos."},{icon:"\uD83E\uDDE0",title:"Salud mental juvenil",desc:"Apoya a organizaciones que trabajan con j\xf3venes que sufren ansiedad, depresi\xf3n o aislamiento social."}],skills:["Estabilidad mental","Empat\xeda sin absorber","Cuidado concreto","Capacidad de estar en silencio","Conciencia higi\xe9nica","Discreci\xf3n","Calma bajo presi\xf3n"],suitedFor:["T\xfa que est\xe1s considerando un futuro en sanidad, cuidados sociales, psicolog\xeda o salud p\xfablica.","T\xfa que tienes estabilidad mental y autoconocimiento.","T\xfa que no temes lo f\xedsico, lo fr\xe1gil, lo humano.","T\xfa que quieres encontrarte con la vida en toda su amplitud, incluido el envejecimiento y los finales."],practical:{duration:"6–12 meses. Algunos proyectos paliativos requieren al menos 9 meses para crear continuidad con los pacientes.",languages:"El idioma local suele ser esencial: las relaciones se construyen en la conversaci\xf3n. El ingl\xe9s rara vez alcanza en el cuidado diario.",requirements:"La estabilidad mental y la autorreflexi\xf3n son importantes. A menudo se requiere certificado de antecedentes penales. La experiencia cuidando familiares cercanos es valorada."}}},it:{"socialt-arbete":{name:"Lavoro sociale e inclusione",tagline:"Sostieni le persone in situazioni vulnerabili e contribuisci a una societ\xe0 pi\xf9 inclusiva.",hero:{heading:"Le persone prima di tutto",sub:"Come volontario CES nel lavoro sociale, lavori a stretto contatto con persone in situazioni di vita difficili: senzatetto, dipendenze, problemi di salute mentale, solitudine o isolamento sociale. Diventi parte di una squadra che costruisce dignit\xe0 e fiducia, una relazione alla volta."},stats:[{value:"6–12 mesi",label:"Durata tipica"},{value:"~30%",label:"Di tutti i posti CES"},{value:"0 €",label:"Costo per te"}],body:"Il lavoro sociale \xe8 una delle categorie pi\xf9 grandi del Corpo Europeo di Solidariet\xe0. Raramente richiede una \"competenza\" specifica: richiede presenza. Preparare la colazione in un dormitorio. Accompagnare qualcuno in banca. Parlare, ascoltare, esserci.\n\nI progetti esistono in tutta Europa: da dormitori urbani e alloggi protetti a Berlino e Lisbona, a iniziative locali pi\xf9 piccole nelle aree rurali. Molti progetti si rivolgono a gruppi specifici: senzatetto, cittadini UE in situazioni vulnerabili, persone con problemi di dipendenza, genitori single, persone che lasciano strutture di accoglienza.\n\nDi solito ricevi un'area di responsabilit\xe0 concreta dopo un periodo di introduzione. L'organizzazione ospitante ti forma in modo continuativo e lavori sempre accanto a personale esperto.",examples:[{icon:"\uD83C\uDFE0",title:"Dormitori e alloggi protetti",desc:"Aiuta con le routine quotidiane, i pasti, le attivit\xe0 comunitarie e a creare un ambiente sicuro per i residenti."},{icon:"\uD83E\uDD32",title:"Lavoro di strada",desc:"Partecipa al lavoro sul campo per incontrare i senzatetto direttamente in strada: distribuisci cibo, vestiti, articoli per l'igiene e informazioni."},{icon:"☕",title:"Spazi di incontro sociale",desc:"Gestisci caff\xe8 sociali, case delle attivit\xe0 o centri diurni dove le persone possono rifugiarsi dal freddo e trovare comunit\xe0."},{icon:"\uD83E\uDDE0",title:"Supporto alla salute mentale",desc:"Sii una persona di supporto in servizi a bassa soglia, attivit\xe0 di gruppo o accompagnamento individuale sotto supervisione."},{icon:"\uD83C\uDF5E",title:"Banchi alimentari",desc:"Organizza e distribuisci cibo a famiglie in difficolt\xe0 economica: una delle forme di aiuto pi\xf9 concrete."},{icon:"\uD83C\uDFAF",title:"Mentoring",desc:"Sii una figura stabile per giovani o adulti che necessitano supporto nella reintegrazione o in un cambiamento di vita."}],skills:["Empatia e ascolto","Gestione dei conflitti","Ascolto attivo","Pazienza","Stabilire confini","Comunicazione interculturale","Capacit\xe0 di stare nel disagio"],suitedFor:["Tu che vuoi lavorare direttamente con le persone, non dietro uno schermo.","Tu che ti interessano le questioni sociali, l'uguaglianza o il lavoro sociale come professione futura.","Tu che hai la stabilit\xe0 mentale per ascoltare storie pesanti senza spezzarti.","Tu che sei disposto a imparare, non a sistemare tutto subito."],practical:{duration:"La maggior parte dei progetti dura 6–12 mesi. I progetti brevi (2–4 mesi) esistono ma sono meno comuni.",languages:"L'inglese di solito basta come lingua iniziale. Si prevede che tu impari le basi della lingua locale: senza, il lavoro quotidiano si complica.",requirements:"Nessun requisito formale, ma la stabilit\xe0 personale \xe8 importante. Alcuni progetti richiedono il certificato del casellario giudiziale. L'esperienza precedente nel volontariato \xe8 apprezzata, ma non necessaria."}},"migration-integration":{name:"Migrazione e integrazione",tagline:"Aiuta i nuovi arrivati a trovare il loro posto in una nuova societ\xe0: lingua, cultura, diritti, vita quotidiana.",hero:{heading:"Un ponte tra mondi",sub:"Come volontario CES nella migrazione e integrazione, lavori accanto a persone appena arrivate in un nuovo paese: rifugiati, richiedenti asilo, minori non accompagnati, cittadini UE in situazioni vulnerabili. Li aiuti a muoversi tra le istituzioni, a imparare la lingua, a trovare la loro nuova vita quotidiana."},stats:[{value:"6–12 mesi",label:"Durata tipica"},{value:"25+",label:"Paesi con progetti attivi"},{value:"0 €",label:"Costo per te"}],body:"La migrazione \xe8 una delle pi\xf9 grandi questioni sociali europee e una delle aree pi\xf9 significative in cui lavorare. I progetti CES esistono in centri di accoglienza, alloggi per richiedenti asilo, case per minori non accompagnati, centri di integrazione e organizzazioni che lavorano con persone senza documenti.\n\nIl lavoro \xe8 concreto e variegato: caff\xe8 linguistici, supporto ai compiti per i bambini, informazioni legali di base, attivit\xe0 ricreative, gruppi di donne, sensibilizzazione sui diritti. Molti progetti sono gestiti da ONG che lavorano in parallelo al sistema pubblico, ma anche da chiese, sindacati e centri comunali.\n\nI progetti che riguardano l'accoglienza di rifugiati richiedono spesso una supervisione specifica: lavori con persone che a volte hanno vissuto traumi e l'organizzazione ti offre supporto continuo. Non si prevede che tu sia un terapeuta. Si prevede che tu sia un essere umano presente.",examples:[{icon:"\uD83D\uDCAC",title:"Caff\xe8 linguistici e lezioni",desc:"Guida incontri linguistici informali dove i partecipanti praticano la lingua locale attraverso conversazioni quotidiane, giochi e temi."},{icon:"\uD83D\uDCCB",title:"Informazioni sui diritti",desc:"Aiuta le persone a capire come richiedere permessi di soggiorno, trovare alloggio, registrarsi presso le autorit\xe0."},{icon:"\uD83D\uDC68‍\uD83D\uDC69‍\uD83D\uDC67",title:"Attivit\xe0 per famiglie",desc:"Organizza gite, eventi culturali e attivit\xe0 che costruiscono comunit\xe0 tra nuovi arrivati e popolazione locale."},{icon:"\uD83D\uDCD6",title:"Supporto ai compiti per bambini",desc:"Sostieni bambini e ragazzi con i compiti, la lettura e l'apprendimento della lingua locale. Spesso nei doposcuola."},{icon:"\uD83C\uDF93",title:"Educazione per adulti",desc:"Assisti nei corsi di alfabetizzazione informatica, ricerca lavoro, teoria della patente o conoscenze pratiche quotidiane."},{icon:"\uD83E\uDD1D",title:"Programmi di amicizia",desc:"Costruisci relazioni uno a uno tra nuovi arrivati e residenti locali: una delle misure di integrazione pi\xf9 efficaci."}],skills:["Competenza interculturale","Pazienza con le barriere linguistiche","Diplomazia","Capacit\xe0 pedagogiche","Empatia","Capacit\xe0 di semplificare informazioni complesse","Umilt\xe0 culturale"],suitedFor:["Tu che sei curioso di altre culture e vuoi diventare collega di persone da tutto il mondo.","Tu che credi in un'Europa pi\xf9 aperta e solidale.","Tu che riesci a comunicare anche quando la lingua non basta.","Tu che riesci a gestire la frustrazione burocratica senza perdere la speranza."],practical:{duration:"6–12 mesi. Alcuni progetti di mentoring a lungo termine o di supporto ai bambini richiedono almeno 9 mesi.",languages:"L'inglese come lingua di lavoro \xe8 comune, ma la lingua locale \xe8 essenziale a lungo termine. Alcuni progetti valorizzano particolarmente l'arabo, il dari, l'ucraino o altre lingue.",requirements:"La stabilit\xe0 mentale \xe8 centrale. Alcuni progetti richiedono un colloquio preliminare. L'esperienza con persone di provenienze diverse \xe8 apprezzata."}},"utbildning-ungdom":{name:"Educazione e giovent\xf9",tagline:"Ispira la prossima generazione: in classi, centri giovanili e ambienti di apprendimento informale.",hero:{heading:"Accendi scintille negli altri",sub:"Come volontario CES in educazione e giovent\xf9, lavori con bambini, adolescenti o giovani adulti: nelle scuole, nei centri giovanili, nelle organizzazioni giovanili o in ambienti di apprendimento informale. Diventi un modello, un mentore, a volte un fratello o una sorella maggiore."},stats:[{value:"6–12 mesi",label:"Durata tipica"},{value:"~25%",label:"Di tutti i posti CES"},{value:"0 €",label:"Costo per te"}],body:"Questa \xe8 una delle aree pi\xf9 ampie e popolari del CES. I progetti spaziano dalle scuole regolari (dove di solito sei assistente linguistico o aiuti in classe) ai centri giovanili, alle organizzazioni giovanili e ai gruppi che lavorano con l'apprendimento informale: l'apprendimento che avviene fuori dalla scuola, attraverso attivit\xe0, giochi, laboratori e conversazioni.\n\nMolte scuole europee accolgono volontari CES per dare agli alunni un contatto autentico con un'altra lingua e cultura europea. Non sei insegnante: sei un giovane adulto presente che introduce l'inglese, lo svedese o la tua cultura, spesso attraverso la conversazione e il gioco.\n\nIl settore giovanile \xe8 altrettanto importante. Si tratta di essere una presenza stabile per i giovani che forse non hanno sempre quel sostegno a casa: condurre attivit\xe0, ascoltare, organizzare uscite, costruire mentoring nel tempo.",examples:[{icon:"\uD83C\uDFEB",title:"Assistente linguistico a scuola",desc:"Sostieni gli insegnanti di lingue in classe, guida piccoli gruppi, aiuta gli studenti che hanno bisogno di supporto extra. Spesso in lingue UE o inglese."},{icon:"\uD83C\uDFAE",title:"Centri e club giovanili",desc:"Guida attivit\xe0, giochi, laboratori e conversazioni con gli adolescenti. Costruisci mentoring duraturi nel tempo."},{icon:"\uD83C\uDFA8",title:"Laboratori creativi",desc:"Gestisci laboratori d'arte, musica, teatro o artigianato come strumenti di sviluppo personale ed espressione."},{icon:"\uD83D\uDCD6",title:"Supporto compiti",desc:"Sostieni bambini e ragazzi che hanno bisogno di aiuto extra con i compiti, spesso combinato con attivit\xe0 ricreative."},{icon:"\uD83C\uDF10",title:"Scambi internazionali",desc:"Aiuta a organizzare scambi Erasmus+, conferenze giovanili e campagne di consapevolezza europea."},{icon:"⚽",title:"Sport e attivit\xe0 all'aperto",desc:"Guida attivit\xe0 sportive e all'aperto come strumenti di inclusione, salute e lavoro di squadra."}],skills:["Sensibilit\xe0 pedagogica","Energia e gioco","Leadership di gruppo","Risoluzione conflitti tra bambini/ragazzi","Risoluzione creativa dei problemi","Pazienza","Capacit\xe0 di essere un modello"],suitedFor:["Tu che ti piacciono bambini e ragazzi e ti riesce facile comunicare con loro.","Tu che stai pensando a un futuro come insegnante, educatore, assistente sociale o psicologo infantile.","Tu che hai energia e idee, e reggi il caos quando serve.","Tu che vuoi scoprire la tua societ\xe0 attraverso occhi pi\xf9 giovani."],practical:{duration:"9–12 mesi \xe8 il pi\xf9 comune, spesso legato all'anno scolastico. I progetti estivi (2–3 mesi) esistono ma principalmente per campi e attivit\xe0 ricreative.",languages:"L'inglese basta in molti ruoli di assistente linguistico. Per il lavoro giovanile normalmente devi imparare la lingua locale: \xe8 cos\xec che si costruiscono le relazioni.",requirements:"Molte scuole richiedono il certificato del casellario giudiziale. L'esperienza con bambini (campi estivi, scout, allenatori sportivi) \xe8 apprezzata."}},"miljo-hallbarhet":{name:"Ambiente e sostenibilit\xe0",tagline:"Lavora concretamente su clima, biodiversit\xe0, agricoltura biologica e comunit\xe0 sostenibili.",hero:{heading:"Per un pianeta che regga",sub:"Come volontario CES in ambiente e sostenibilit\xe0, lavori su questioni climatiche, conservazione della natura, agricoltura biologica o economia circolare. Diventi parte della transizione verde europea: in riserve naturali, in fattorie biologiche, in organizzazioni ambientali o in citt\xe0 che portano avanti progetti sostenibili."},stats:[{value:"3–12 mesi",label:"Ampia variazione"},{value:"Rurale",label:"Molti progetti fuori citt\xe0"},{value:"0 €",label:"Costo per te"}],body:"Quest'area \xe8 cresciuta molto negli ultimi anni. I progetti CES esistono nella conservazione della natura (gestione forestale, ripristino di zone umide, monitoraggio degli uccelli), agricoltura biologica (fattorie che ospitano volontari in stile WWOOF), educazione ambientale (centri che ospitano classi scolastiche), attivismo climatico (ONG e organizzazioni di advocacy) e sviluppo urbano sostenibile.\n\nMolti progetti sono in zone rurali, a volte in regioni remote: qualcosa di cui essere consapevoli. Significa contatto stretto con la natura, ma anche che puoi essere abbastanza isolato da citt\xe0 grandi e vita notturna. Chi cerca un'esperienza rurale autentica si sentir\xe0 a casa; chi vuole atmosfera urbana dovrebbe cercare progetti in citt\xe0.\n\nIl lavoro \xe8 spesso fisico: pianti, scavi, poti, osservi, documenti. Impari nuove tecniche e ottieni conoscenze pratiche che porti con te.",examples:[{icon:"\uD83C\uDF33",title:"Conservazione forestale e naturale",desc:"Piantumazione, diradamento, ripristino di biotopi, censimenti di uccelli, monitoraggio di specie protette."},{icon:"\uD83C\uDF3E",title:"Agricoltura biologica",desc:"Impara permacultura, agroecologia e agricoltura sostenibile attraverso il lavoro pratico in fattorie e orti."},{icon:"\uD83D\uDC1D",title:"Biodiversit\xe0",desc:"Sostieni progetti su api, farfalle, piccoli uccelli: censimenti, creazione di habitat, eventi pubblici."},{icon:"\uD83D\uDCE2",title:"Educazione ambientale",desc:"Guida attivit\xe0 pedagogiche per classi scolastiche e pubblico in centri natura o scuole all'aperto."},{icon:"♻️",title:"Economia circolare",desc:"Lavora con progetti di riuso, repair caf\xe9s, negozi dell'usato e iniziative contro lo spreco alimentare."},{icon:"\uD83C\uDF0D",title:"Attivismo climatico",desc:"Sostieni organizzazioni che portano avanti questioni climatiche attraverso campagne, advocacy e dialogo comunitario."}],skills:["Risoluzione pratica dei problemi","Resistenza fisica","Conoscenze scientifiche di base","Pazienza (il lavoro in natura \xe8 lento)","Lavoro di squadra all'aperto","Pensiero a lungo termine","Capacit\xe0 di adattamento"],suitedFor:["Tu che ti trovi bene all'aperto e non hai paura del lavoro fisico o del brutto tempo.","Tu che vuoi tradurre l'impegno climatico in azione concreta.","Tu che stai pensando a un futuro in ambiente, biologia, agronomia o sostenibilit\xe0.","Tu che riesci a goderti il silenzio e il ritmo di un ambiente rurale."],practical:{duration:"Grande variazione. Esistono progetti stagionali brevi (2–3 mesi durante raccolta o piantumazione) accanto a progetti annuali. Pensa alla stagione quando ti candidi.",languages:"L'inglese basta in molti progetti ambientali internazionali. In piccole fattorie biologiche, una lingua locale di base pu\xf2 essere pi\xf9 importante.",requirements:"Nessun requisito formale. Ma capacit\xe0 fisica, patente (a volte) e stabilit\xe0 in ambiente rurale sono apprezzati. Considera allergie (api, fieno, sole)."}},"kultur-konst":{name:"Cultura e arte",tagline:"Usa la creativit\xe0 come strumento di cambiamento: arte, media, teatro, cinema, patrimonio culturale.",hero:{heading:"Creativit\xe0 che cambia le cose",sub:"Come volontario CES in cultura e arte, lavori in musei, centri culturali, festival cinematografici, teatri, organizzazioni mediatiche o progetti artistici comunitari. Aiuti la cultura a raggiungere pi\xf9 persone, e ottieni esperienza professionale in un settore altrimenti difficile da entrare."},stats:[{value:"6–12 mesi",label:"Durata tipica"},{value:"Citt\xe0",label:"Soprattutto progetti urbani"},{value:"0 €",label:"Costo per te"}],body:"L'area culturale all'interno del CES \xe8 ampia e variegata. Include sia la cultura istituzionale tradizionale (musei, gallerie, teatri, festival cinematografici, patrimonio) sia forme pi\xf9 attiviste e community-based: arte urbana, teatro comunitario, video come strumento per voci marginalizzate, progetti documentari con rifugiati, collettivi artigianali.\n\nPer molti che vogliono entrare nel settore culturale, il CES \xe8 un'eccellente piattaforma di lancio. Ottieni vera esperienza lavorativa in un museo, una redazione culturale o una produzione cinematografica: qualcosa che altrimenti richiede stage spesso non retribuiti o legati agli studi.\n\nVale la pena notare che questi posti sono spesso popolari, quindi la concorrenza pu\xf2 essere dura. Candidarsi presto e avere una motivazione chiara sul perch\xe9 la cultura specificamente \xe8 utile.",examples:[{icon:"\uD83C\uDFDB️",title:"Musei e gallerie",desc:"Sostieni il lavoro con il pubblico, la produzione di mostre, le attivit\xe0 pedagogiche, la comunicazione e gli eventi."},{icon:"\uD83C\uDFAC",title:"Cinema e media",desc:"Aiuta nei festival cinematografici, nei progetti documentari, nelle scuole di cinema giovanili o nei produttori di media comunitari."},{icon:"\uD83C\uDFAD",title:"Teatro e arti performative",desc:"Assisti nelle produzioni, nei gruppi di teatro giovanile, nel teatro comunitario o nel teatro di strada in zone marginalizzate."},{icon:"\uD83C\uDFB5",title:"Musica e didattica musicale",desc:"Sostieni scuole di musica, progetti corali, organizzazione di concerti o iniziative di musicoterapia."},{icon:"\uD83D\uDCDA",title:"Biblioteche e letteratura",desc:"Promuovi la lettura, le visite di autori, la scrittura creativa per giovani o i laboratori di narrazione."},{icon:"\uD83D\uDEE0️",title:"Artigianato e tradizioni",desc:"Impara e aiuta a trasmettere tradizioni locali: ceramica, falegnameria, tessitura, cucina, in centri del patrimonio."}],skills:["Pensiero creativo","Comunicazione visiva","Gestione progetti","Storytelling","Competenza social media","Disciplina artistica","Sensibilit\xe0 estetica interculturale"],suitedFor:["Tu che hai interesse artistico, accademico o pratico.","Tu che stai pensando a un futuro in arte, cinema, teatro, media, musei o politica culturale.","Tu che vuoi costruire portfolio e rete in un settore difficile da raggiungere.","Tu che vedi la cultura come strumento di cambiamento, non solo intrattenimento."],practical:{duration:"6–12 mesi \xe8 il pi\xf9 comune, a volte sincronizzato con le stagioni culturali. I progetti di festival possono essere pi\xf9 brevi e intensi.",languages:"L'inglese basta spesso in contesti internazionali (musei, festival), ma per il lavoro comunitario la lingua locale \xe8 la chiave.",requirements:"L'esperienza artistica \xe8 apprezzata ma non sempre necessaria. Molti progetti vogliono vedere motivazione e un portfolio creativo (anche basilare)."}},"halsa-omsorg":{name:"Salute e cura",tagline:"Contribuisci al benessere: salute pubblica, assistenza agli anziani, supporto alla disabilit\xe0, cure palliative.",hero:{heading:"Una presenza che cura",sub:"Come volontario CES in salute e cura, lavori con anziani, persone con disabilit\xe0, persone in cure palliative o organizzazioni orientate alla salute pubblica. Non sei personale sanitario: sei una presenza umana che integra e alleggerisce i professionisti."},stats:[{value:"6–12 mesi",label:"Durata tipica"},{value:"UE + 3\xb0",label:"Dentro e fuori UE"},{value:"0 €",label:"Costo per te"}],body:"Salute e cura \xe8 un'area dove la tua presenza conta molto, forse pi\xf9 di quanto pensi. Spesso non si tratta di interventi medici, ma di compagnia. Leggere ad alta voce a un'anziana. Essere compagno di nuoto di un uomo con disabilit\xe0 intellettiva. Tenere la mano di qualcuno la cui vita si avvicina alla fine.\n\nI progetti esistono in case di riposo, attivit\xe0 diurne per persone con disabilit\xe0, hospice, ambulatori a bassa soglia per gruppi vulnerabili, organizzazioni che lavorano nella salute pubblica o nella prevenzione dell'HIV. Alcuni lavorano specificamente con giovani con problemi di salute mentale.\n\n\xc8 un'area che richiede stabilit\xe0 mentale. A volte incontri malattia, vecchiaia e morte. L'organizzazione ospitante ti offre supervisione e supporto, e non lavori mai da solo in situazioni pesanti. Ma \xe8 importante riflettere onestamente se hai le risorse per affrontarlo.",examples:[{icon:"\uD83D\uDC75",title:"Assistenza agli anziani",desc:"Compagnia, lettura ad alta voce, passeggiate, attivit\xe0 comunitarie in case di riposo o con anziani isolati."},{icon:"♿",title:"Supporto alla disabilit\xe0",desc:"Assisti nelle attivit\xe0 diurne, accompagna nelle gite, sii compagno di nuoto o di attivit\xe0 ricreative."},{icon:"\uD83D\uDD4A️",title:"Cure palliative e hospice",desc:"Sii una presenza tranquilla per persone alla fine della vita. Sono inclusi sostanziale supervisione e supporto."},{icon:"\uD83C\uDFE5",title:"Ambulatori a bassa soglia",desc:"Aiuta in ambulatori che lavorano con senzatetto, persone con dipendenze o persone senza documenti in questioni di salute."},{icon:"\uD83D\uDCE2",title:"Lavoro di salute pubblica",desc:"Informa su salute sessuale, salute mentale, dipendenze o vaccinazioni: spesso in scuole o eventi."},{icon:"\uD83E\uDDE0",title:"Salute mentale giovanile",desc:"Sostieni organizzazioni che lavorano con giovani che soffrono di ansia, depressione o isolamento sociale."}],skills:["Stabilit\xe0 mentale","Empatia senza assorbire","Cura concreta","Capacit\xe0 di stare in silenzio","Consapevolezza igienica","Discrezione","Calma sotto pressione"],suitedFor:["Tu che stai pensando a un futuro in sanit\xe0, assistenza sociale, psicologia o salute pubblica.","Tu che hai stabilit\xe0 mentale e auto-consapevolezza.","Tu che non hai paura del fisico, del fragile, dell'umano.","Tu che vuoi incontrare la vita in tutta la sua ampiezza, inclusi vecchiaia e conclusioni."],practical:{duration:"6–12 mesi. Alcuni progetti palliativi richiedono almeno 9 mesi per creare continuit\xe0 con i pazienti.",languages:"La lingua locale \xe8 spesso essenziale: le relazioni si costruiscono nella conversazione. L'inglese raramente basta nell'assistenza quotidiana.",requirements:"La stabilit\xe0 mentale e l'auto-riflessione sono importanti. Spesso \xe8 richiesto il certificato del casellario giudiziale. L'esperienza di cura di familiari \xe8 apprezzata."}}},de:{"socialt-arbete":{name:"Sozialarbeit & Inklusion",tagline:"Unterst\xfctze Menschen in vulnerablen Situationen und trage zu einer inklusiveren Gesellschaft bei.",hero:{heading:"Menschen zuerst",sub:"Als ESK-Freiwillige:r in der Sozialarbeit arbeitest du eng mit Menschen in schwierigen Lebenssituationen: Obdachlosigkeit, Sucht, psychische Erkrankungen, Einsamkeit oder soziale Isolation. Du wirst Teil eines Teams, das W\xfcrde und Vertrauen aufbaut, eine Beziehung nach der anderen."},stats:[{value:"6–12 Mon",label:"Typische Dauer"},{value:"~30%",label:"Aller ESK-Pl\xe4tze"},{value:"0 €",label:"Kosten f\xfcr dich"}],body:'Sozialarbeit ist eine der gr\xf6\xdften Kategorien im Europ\xe4ischen Solidarit\xe4tskorps. Sie verlangt selten besondere "Expertise" — sie verlangt Anwesenheit. Fr\xfchst\xfcck in einer Notunterkunft zubereiten. Jemanden zur Bank begleiten. Sprechen, zuh\xf6ren, da sein.\n\nProjekte gibt es in ganz Europa: von st\xe4dtischen Notunterk\xfcnften und betreuten Wohnformen in Berlin und Lissabon bis hin zu kleineren lokalen Initiativen im l\xe4ndlichen Raum. Viele Projekte richten sich an bestimmte Gruppen: Obdachlose, EU-B\xfcrger in vulnerablen Situationen, Menschen mit Suchtproblemen, Alleinerziehende, Menschen, die institutionelle Betreuung verlassen.\n\nNormalerweise erh\xe4ltst du nach einer Einf\xfchrungsphase einen konkreten Verantwortungsbereich. Die Aufnahmeorganisation bildet dich laufend fort, und du arbeitest immer neben erfahrenem Personal.',examples:[{icon:"\uD83C\uDFE0",title:"Notunterk\xfcnfte & betreutes Wohnen",desc:"Hilf bei t\xe4glichen Routinen, Mahlzeiten, Gemeinschaftsaktivit\xe4ten und beim Schaffen einer sicheren Umgebung f\xfcr die Bewohner."},{icon:"\uD83E\uDD32",title:"Aufsuchende Arbeit",desc:"Geh mit auf Feldarbeit, um Obdachlose direkt auf der Stra\xdfe zu treffen — verteile Essen, Kleidung, Hygieneartikel und Informationen."},{icon:"☕",title:"Soziale Treffpunkte",desc:"Betreibe Sozialcaf\xe9s, Aktivit\xe4tsh\xe4user oder Tageszentren, in denen Menschen aus der K\xe4lte kommen und Gemeinschaft finden k\xf6nnen."},{icon:"\uD83E\uDDE0",title:"Unterst\xfctzung bei psychischer Gesundheit",desc:"Sei Bezugsperson in niedrigschwelligen Angeboten, Gruppenaktivit\xe4ten oder Einzelbegleitung unter Supervision."},{icon:"\uD83C\uDF5E",title:"Tafeln & Verteilung",desc:"Organisiere und verteile Lebensmittel an Familien in finanzieller Notlage — eine der konkretesten Hilfeformen."},{icon:"\uD83C\uDFAF",title:"Mentoring",desc:"Sei eine stabile Bezugsperson f\xfcr junge Menschen oder Erwachsene, die Unterst\xfctzung bei der Wiedereingliederung oder Lebensver\xe4nderung brauchen."}],skills:["Empathie & Aufmerksamkeit","Konfliktmanagement","Aktives Zuh\xf6ren","Geduld","Grenzen setzen","Interkulturelle Kommunikation","Aushalten von Unbehagen"],suitedFor:["Du, der direkt mit Menschen arbeiten m\xf6chte — nicht hinter einem Bildschirm.","Du, der/die sich f\xfcr soziale Fragen, Gleichheit oder Sozialarbeit als Beruf interessiert.","Du, der/die die mentale Stabilit\xe4t hat, schwere Geschichten zu h\xf6ren, ohne daran zu zerbrechen.","Du, der/die bereit ist zu lernen — nicht alles sofort zu l\xf6sen."],practical:{duration:"Die meisten Projekte dauern 6–12 Monate. K\xfcrzere Projekte (2–4 Monate) gibt es, sind aber weniger \xfcblich.",languages:"Englisch reicht meist als Startsprache. Es wird erwartet, dass du Grundlagen der Landessprache lernst — ohne sie wird der Alltag schwierig.",requirements:"Keine formalen Anforderungen, aber pers\xf6nliche Stabilit\xe4t ist wichtig. Manche Projekte verlangen ein F\xfchrungszeugnis. Vorherige Freiwilligenerfahrung ist von Vorteil, aber nicht notwendig."}},"migration-integration":{name:"Migration & Integration",tagline:"Hilf Neuank\xf6mmlingen, ihren Platz in einer neuen Gesellschaft zu finden — Sprache, Kultur, Rechte, Alltag.",hero:{heading:"Eine Br\xfccke zwischen Welten",sub:"Als ESK-Freiwillige:r in Migration und Integration arbeitest du neben Menschen, die gerade in ein neues Land gekommen sind: Gefl\xfcchtete, Asylsuchende, unbegleitete Minderj\xe4hrige, EU-B\xfcrger in vulnerablen Situationen. Du hilfst ihnen, sich bei Beh\xf6rden zurechtzufinden, die Sprache zu lernen, ihren neuen Alltag zu finden."},stats:[{value:"6–12 Mon",label:"Typische Dauer"},{value:"25+",label:"L\xe4nder mit aktiven Projekten"},{value:"0 €",label:"Kosten f\xfcr dich"}],body:"Migration ist eine der gr\xf6\xdften sozialen Fragen Europas — und einer der sinnstiftendsten Bereiche zum Arbeiten. ESK-Projekte gibt es in Erstaufnahmezentren, Asylunterk\xfcnften, Jugendhilfeeinrichtungen f\xfcr unbegleitete Minderj\xe4hrige, Integrationszentren und Organisationen, die mit Menschen ohne Papiere arbeiten.\n\nDie Arbeit ist konkret und vielf\xe4ltig: Sprachcaf\xe9s, Hausaufgabenhilfe f\xfcr Kinder, juristische Grundinformationen, Freizeitaktivit\xe4ten, Frauengruppen, Aufkl\xe4rung \xfcber Rechte. Viele Projekte werden von NGOs parallel zum \xf6ffentlichen System gef\xfchrt, aber auch von Kirchen, Gewerkschaften und kommunalen Zentren.\n\nProjekte zur Fl\xfcchtlingsaufnahme ben\xf6tigen oft besondere Supervision — du arbeitest mit Menschen, die manchmal Traumata erlebt haben, und die Organisation bietet laufend Unterst\xfctzung. Es wird nicht erwartet, dass du Therapeut:in bist. Es wird erwartet, dass du ein anwesender Mensch bist.",examples:[{icon:"\uD83D\uDCAC",title:"Sprachcaf\xe9s & Unterricht",desc:"Leite informelle Sprachtreffen, bei denen Teilnehmende die Landessprache durch Alltagsgespr\xe4che, Spiele und Themen \xfcben."},{icon:"\uD83D\uDCCB",title:"Informationen \xfcber Rechte",desc:"Hilf Menschen zu verstehen, wie sie Aufenthaltstitel beantragen, Wohnungen finden, sich bei Beh\xf6rden registrieren."},{icon:"\uD83D\uDC68‍\uD83D\uDC69‍\uD83D\uDC67",title:"Familienaktivit\xe4ten",desc:"Organisiere Ausfl\xfcge, kulturelle Veranstaltungen und Aktivit\xe4ten, die Gemeinschaft zwischen Neuank\xf6mmlingen und lokaler Bev\xf6lkerung schaffen."},{icon:"\uD83D\uDCD6",title:"Hausaufgabenhilfe f\xfcr Kinder",desc:"Unterst\xfctze Kinder und Jugendliche bei Schularbeiten, Lesen und beim Erlernen der Landessprache. Oft in Nachmittagsangeboten."},{icon:"\uD83C\uDF93",title:"Erwachsenenbildung",desc:"Assistiere in Kursen zu Computerkenntnissen, Jobsuche, F\xfchrerscheintheorie oder praktischem Alltagswissen."},{icon:"\uD83E\uDD1D",title:"Patenschaftsprogramme",desc:"Baue Eins-zu-eins-Beziehungen zwischen Neuank\xf6mmlingen und Einheimischen auf — eine der wirksamsten Integrationsma\xdfnahmen."}],skills:["Interkulturelle Kompetenz","Geduld mit Sprachbarrieren","Diplomatie","P\xe4dagogisches Geschick","Empathie","F\xe4higkeit, komplexe Informationen zu vereinfachen","Kulturelle Demut"],suitedFor:["Du, der/die neugierig auf andere Kulturen ist und mit Menschen aus aller Welt zusammenarbeiten will.","Du, der/die an ein offeneres und solidarischeres Europa glaubt.","Du, der/die kommunizieren kann, auch wenn die Sprache nicht reicht.","Du, der/die b\xfcrokratische Frustration aushalten kann, ohne die Hoffnung zu verlieren."],practical:{duration:"6–12 Monate. Manche Projekte mit langfristiger Patenschaft oder Kinderbetreuung verlangen mindestens 9 Monate.",languages:"Englisch als Arbeitssprache ist \xfcblich, aber die Landessprache ist langfristig entscheidend. Manche Projekte sch\xe4tzen Arabisch, Dari, Ukrainisch oder andere Sprachen besonders.",requirements:"Mentale Stabilit\xe4t ist zentral. Manche Projekte verlangen ein Vorgespr\xe4ch. Erfahrung mit Menschen unterschiedlicher Herkunft ist von Vorteil."}},"utbildning-ungdom":{name:"Bildung & Jugend",tagline:"Inspiriere die n\xe4chste Generation — in Klassenzimmern, Jugendzentren, informellen Lernumgebungen.",hero:{heading:"Z\xfcnde Funken in anderen",sub:"Als ESK-Freiwillige:r in Bildung und Jugend arbeitest du mit Kindern, Jugendlichen oder jungen Erwachsenen: in Schulen, Jugendzentren, Jugendorganisationen oder informellen Lernumgebungen. Du wirst zum Vorbild, zum Mentor, manchmal zur gro\xdfen Schwester oder zum gro\xdfen Bruder."},stats:[{value:"6–12 Mon",label:"Typische Dauer"},{value:"~25%",label:"Aller ESK-Pl\xe4tze"},{value:"0 €",label:"Kosten f\xfcr dich"}],body:"Dies ist einer der breitesten und beliebtesten Bereiche im ESK. Die Projekte reichen von regul\xe4ren Schulen (wo du meist Sprachassistent:in bist oder im Klassenzimmer hilfst) bis zu Jugendzentren, Jugendorganisationen und Gruppen, die mit informellem Lernen arbeiten — Lernen, das au\xdferhalb der Schule stattfindet, durch Aktivit\xe4ten, Spiele, Workshops und Gespr\xe4che.\n\nViele europ\xe4ische Schulen nehmen ESK-Freiwillige auf, um den Sch\xfcler:innen authentischen Kontakt mit einer anderen europ\xe4ischen Sprache und Kultur zu geben. Du bist keine Lehrkraft — du bist ein:e pr\xe4sente:r junge:r Erwachsene:r, der/die Englisch, Schwedisch oder die eigene Kultur einbringt, oft durch Gespr\xe4ch und Spiel.\n\nDer Jugendsektor ist genauso wichtig. Es geht darum, eine stabile Pr\xe4senz f\xfcr junge Menschen zu sein, die diese Unterst\xfctzung zu Hause vielleicht nicht immer haben — Aktivit\xe4ten leiten, zuh\xf6ren, Ausfl\xfcge organisieren, Mentoring \xfcber Zeit aufbauen.",examples:[{icon:"\uD83C\uDFEB",title:"Sprachassistenz in der Schule",desc:"Unterst\xfctze Sprachlehrkr\xe4fte im Klassenzimmer, leite kleinere Gruppen, hilf Sch\xfclern, die zus\xe4tzliche Unterst\xfctzung brauchen. Oft in EU-Sprachen oder Englisch."},{icon:"\uD83C\uDFAE",title:"Jugendzentren & Jugendclubs",desc:"Leite Aktivit\xe4ten, Spiele, Workshops und Gespr\xe4che mit Jugendlichen. Baue dauerhaftes Mentoring \xfcber Zeit auf."},{icon:"\uD83C\uDFA8",title:"Kreative Werkst\xe4tten",desc:"Betreibe Kunst-, Musik-, Theater- oder Handwerksworkshops als Werkzeuge f\xfcr pers\xf6nliche Entwicklung und Ausdruck."},{icon:"\uD83D\uDCD6",title:"Hausaufgabenhilfe",desc:"Unterst\xfctze Kinder und Jugendliche, die zus\xe4tzliche Hilfe bei Schularbeiten brauchen, oft kombiniert mit Freizeitaktivit\xe4ten."},{icon:"\uD83C\uDF10",title:"Internationale Austausche",desc:"Hilf bei der Organisation von Erasmus+-Austauschen, Jugendkonferenzen und europ\xe4ischen Sensibilisierungskampagnen."},{icon:"⚽",title:"Sport & Outdoor-Aktivit\xe4ten",desc:"Leite Sport- und Outdoor-Aktivit\xe4ten als Werkzeuge f\xfcr Inklusion, Gesundheit und Teamarbeit."}],skills:["P\xe4dagogisches Feingef\xfchl","Energie & Verspieltheit","Gruppenleitung","Konfliktl\xf6sung unter Kindern/Jugendlichen","Kreative Probleml\xf6sung","Geduld","F\xe4higkeit, Vorbild zu sein"],suitedFor:["Du, der/die gerne mit Kindern und Jugendlichen umgeht und leicht mit ihnen kommuniziert.","Du, der/die \xfcber eine Zukunft als Lehrer:in, Jugendarbeiter:in, Sozialarbeiter:in oder Kinderpsycholog:in nachdenkt.","Du, der/die Energie und Ideen hat — und Chaos aush\xe4lt, wenn n\xf6tig.","Du, der/die deine eigene Gesellschaft durch j\xfcngere Augen entdecken m\xf6chte."],practical:{duration:"9–12 Monate sind am h\xe4ufigsten, oft an Schuljahre gekoppelt. Sommerprojekte (2–3 Monate) gibt es, aber haupts\xe4chlich f\xfcr Camps und Freizeitaktivit\xe4ten.",languages:"Englisch reicht in vielen Sprachassistenzrollen. F\xfcr Jugendarbeit musst du meist die Landessprache lernen — so baust du Beziehungen auf.",requirements:"Viele Schulen verlangen ein F\xfchrungszeugnis. Erfahrung mit Kindern (Sommercamps, Pfadfinder, Sport) ist von Vorteil."}},"miljo-hallbarhet":{name:"Umwelt & Nachhaltigkeit",tagline:"Arbeite konkret an Klima, Biodiversit\xe4t, Bio-Landwirtschaft und nachhaltigen Gemeinschaften.",hero:{heading:"F\xfcr einen Planeten, der h\xe4lt",sub:"Als ESK-Freiwillige:r in Umwelt und Nachhaltigkeit arbeitest du an Klimafragen, Naturschutz, Bio-Landwirtschaft oder Kreislaufwirtschaft. Du wirst Teil von Europas gr\xfcner Wende — in Naturschutzgebieten, auf Bioh\xf6fen, in Umweltorganisationen oder in St\xe4dten, die Nachhaltigkeitsprojekte vorantreiben."},stats:[{value:"3–12 Mon",label:"Gro\xdfe Dauerspanne"},{value:"L\xe4ndlich",label:"Viele Projekte au\xdferhalb von St\xe4dten"},{value:"0 €",label:"Kosten f\xfcr dich"}],body:"Dieser Bereich ist in den letzten Jahren stark gewachsen. ESK-Projekte gibt es im Naturschutz (Waldbewirtschaftung, Feuchtgebietsrenaturierung, Vogelmonitoring), in der Bio-Landwirtschaft (H\xf6fe, die WWOOF-\xe4hnliche Freiwillige aufnehmen), Umweltbildung (Zentren, die Schulklassen empfangen), Klimaaktivismus (NGOs und Advocacy-Organisationen) und nachhaltiger Stadtentwicklung.\n\nViele Projekte sind im l\xe4ndlichen Raum, manchmal in abgelegenen Regionen — etwas, dessen man sich bewusst sein sollte. Es bedeutet engen Kontakt mit der Natur, aber auch, dass du ziemlich isoliert von gr\xf6\xdferen St\xe4dten und Nachtleben sein kannst. Wer authentische l\xe4ndliche Erfahrung sucht, wird sich zu Hause f\xfchlen; wer urbanen Vibe will, sollte st\xe4dtische Projekte suchen.\n\nDie Arbeit ist oft k\xf6rperlich — du pflanzt, gr\xe4bst, beschneidest, beobachtest, dokumentierst. Du lernst neue Techniken und gewinnst praktisches Wissen, das du mitnimmst.",examples:[{icon:"\uD83C\uDF33",title:"Wald- & Naturschutz",desc:"Pflanzung, Auslichtung, Biotoprenaturierung, Vogelz\xe4hlung, Monitoring gesch\xfctzter Arten."},{icon:"\uD83C\uDF3E",title:"Bio-Landwirtschaft",desc:"Lerne Permakultur, Agrar\xf6kologie und nachhaltige Landwirtschaft durch praktische Arbeit auf H\xf6fen und in G\xe4rten."},{icon:"\uD83D\uDC1D",title:"Biodiversit\xe4t",desc:"Unterst\xfctze Projekte zu Bienen, Schmetterlingen, Kleinv\xf6geln — Z\xe4hlungen, Habitatschaffung, Publikumsveranstaltungen."},{icon:"\uD83D\uDCE2",title:"Umweltbildung",desc:"Leite p\xe4dagogische Aktivit\xe4ten f\xfcr Schulklassen und Publikum in Naturzentren oder Outdoor-Schulen."},{icon:"♻️",title:"Kreislaufwirtschaft",desc:"Arbeite mit Wiederverwendungsprojekten, Repair Caf\xe9s, Second-Hand-L\xe4den und Initiativen gegen Lebensmittelverschwendung."},{icon:"\uD83C\uDF0D",title:"Klimaaktivismus",desc:"Unterst\xfctze Organisationen, die Klimafragen durch Kampagnen, Advocacy und Gemeindedialog vorantreiben."}],skills:["Praktische Probleml\xf6sung","K\xf6rperliche Ausdauer","Wissenschaftliche Grundkenntnisse","Geduld (Naturarbeit dauert)","Outdoor-Teamarbeit","Langfristiges Denken","Anpassungsf\xe4higkeit"],suitedFor:["Du, der/die gerne drau\xdfen ist und keine Angst vor k\xf6rperlicher Arbeit oder schlechtem Wetter hat.","Du, der/die Klimaengagement in konkretes Handeln \xfcbersetzen will.","Du, der/die \xfcber eine Zukunft in Umwelt, Biologie, Agrarwissenschaft oder Nachhaltigkeit nachdenkt.","Du, der/die die Stille und den Rhythmus einer l\xe4ndlichen Umgebung genie\xdfen kann."],practical:{duration:"Gro\xdfe Spanne. Kurze saisonale Projekte (2–3 Monate w\xe4hrend Ernte oder Pflanzung) gibt es neben j\xe4hrlichen Projekten. Denke bei der Bewerbung an die Saison.",languages:"Englisch reicht in vielen internationalen Umweltprojekten. Auf kleineren Bioh\xf6fen k\xf6nnen grundlegende Landessprachkenntnisse wichtiger sein.",requirements:"Keine formalen Anforderungen. Aber k\xf6rperliche Eignung, F\xfchrerschein (manchmal) und Stabilit\xe4t im l\xe4ndlichen Umfeld sind von Vorteil. Allergien (Bienen, Heu, Sonne) bedenken."}},"kultur-konst":{name:"Kultur & Kunst",tagline:"Nutze Kreativit\xe4t als Werkzeug f\xfcr Ver\xe4nderung — Kunst, Medien, Theater, Film, Kulturerbe.",hero:{heading:"Kreativit\xe4t, die Dinge ver\xe4ndert",sub:"Als ESK-Freiwillige:r in Kultur und Kunst arbeitest du in Museen, Kulturzentren, Filmfestivals, Theatern, Medienorganisationen oder gemeinschaftsbasierten Kunstprojekten. Du hilfst, dass Kultur mehr Menschen erreicht — und gewinnst professionelle Erfahrung in einer Branche, die sonst schwer zug\xe4nglich ist."},stats:[{value:"6–12 Mon",label:"Typische Dauer"},{value:"St\xe4dte",label:"Haupts\xe4chlich urbane Projekte"},{value:"0 €",label:"Kosten f\xfcr dich"}],body:"Der Kulturbereich im ESK ist breit und vielf\xe4ltig. Er umfasst sowohl traditionelle institutionelle Kultur — Museen, Galerien, Theater, Filmfestivals, Kulturerbe — als auch aktivistischere, community-basierte Formen: Street Art, Gemeinschaftstheater, Video als Werkzeug f\xfcr marginalisierte Stimmen, Dokumentarprojekte mit Gefl\xfcchteten, Handwerkskollektive.\n\nF\xfcr viele, die in den Kultursektor wollen, ist das ESK ein hervorragendes Sprungbrett. Du bekommst echte Berufserfahrung in einem Museum, einer Kulturredaktion oder einer Filmproduktion — etwas, das sonst Praktika erfordert, die oft unbezahlt oder studiumsgebunden sind.\n\nEs ist erw\xe4hnenswert, dass diese Pl\xe4tze oft beliebt sind, also kann die Konkurrenz hart sein. Fr\xfche Bewerbung und eine klare Motivation, warum gerade Kultur, sind hilfreich.",examples:[{icon:"\uD83C\uDFDB️",title:"Museen & Galerien",desc:"Unterst\xfctze Publikumsarbeit, Ausstellungsproduktion, Bildungsarbeit, Kommunikation und Veranstaltungen."},{icon:"\uD83C\uDFAC",title:"Film & Medien",desc:"Hilf bei Filmfestivals, Dokumentarprojekten, Jugendfilmschulen oder Produzenten von Community-Medien."},{icon:"\uD83C\uDFAD",title:"Theater & darstellende K\xfcnste",desc:"Assistiere bei Produktionen, Jugendtheatergruppen, Community-Theater oder Stra\xdfentheater in marginalisierten Gebieten."},{icon:"\uD83C\uDFB5",title:"Musik & Musikp\xe4dagogik",desc:"Unterst\xfctze Musikschulen, Chorprojekte, Konzertorganisation oder Musiktherapie-Initiativen."},{icon:"\uD83D\uDCDA",title:"Bibliotheken & Literatur",desc:"Betreibe Lesef\xf6rderung, Autorenlesungen, kreatives Schreiben f\xfcr junge Menschen oder Erz\xe4hlwerkst\xe4tten."},{icon:"\uD83D\uDEE0️",title:"Handwerk & Traditionen",desc:"Lerne und hilf, lokale Traditionen weiterzugeben — Keramik, Holzarbeit, Weben, Kochen — in Kulturerbe-Zentren."}],skills:["Kreatives Denken","Visuelle Kommunikation","Projektmanagement","Storytelling","Social-Media-Kompetenz","K\xfcnstlerische Disziplin","Interkulturelle \xe4sthetische Sensibilit\xe4t"],suitedFor:["Du, der/die k\xfcnstlerisches Interesse hat, akademisch oder praktisch.","Du, der/die \xfcber eine Zukunft in Kunst, Film, Theater, Medien, Museen oder Kulturpolitik nachdenkt.","Du, der/die Portfolio und Netzwerk in einer schwer zug\xe4nglichen Branche aufbauen will.","Du, der/die Kultur als Werkzeug f\xfcr Ver\xe4nderung sieht, nicht nur als Unterhaltung."],practical:{duration:"6–12 Monate sind am h\xe4ufigsten, manchmal mit Kultursaisons synchronisiert. Festivalprojekte k\xf6nnen k\xfcrzer und intensiver sein.",languages:"Englisch reicht in internationalen Kontexten (Museen, Festivals) oft, aber f\xfcr Community-Arbeit ist die Landessprache der Schl\xfcssel.",requirements:"K\xfcnstlerische Erfahrung ist von Vorteil, aber nicht immer notwendig. Viele Projekte wollen Motivation und ein kreatives Portfolio sehen (auch grundlegend)."}},"halsa-omsorg":{name:"Gesundheit & Pflege",tagline:"Trage zum Wohlbefinden bei — Volksgesundheit, Altenpflege, Behindertenhilfe, Palliativversorgung.",hero:{heading:"Pr\xe4senz, die heilt",sub:"Als ESK-Freiwillige:r in Gesundheit und Pflege arbeitest du mit \xe4lteren Menschen, Menschen mit Behinderungen, Menschen in der Palliativversorgung oder gesundheitsorientierten Organisationen. Du bist kein medizinisches Personal — du bist eine menschliche Pr\xe4senz, die Fachkr\xe4fte erg\xe4nzt und entlastet."},stats:[{value:"6–12 Mon",label:"Typische Dauer"},{value:"EU + 3.",label:"Innerhalb und au\xdferhalb der EU"},{value:"0 €",label:"Kosten f\xfcr dich"}],body:"Gesundheit und Pflege ist ein Bereich, in dem deine Pr\xe4senz viel bedeutet — vielleicht mehr, als du denkst. Oft geht es nicht um medizinische Interventionen, sondern um Gesellschaft. Einer alten Dame vorlesen. Schwimmkamerad eines Mannes mit geistiger Behinderung sein. Die Hand eines Menschen halten, dessen Leben zu Ende geht.\n\nProjekte gibt es in Pflegeheimen, Tagesangeboten f\xfcr Menschen mit Behinderungen, Hospizen, niedrigschwelligen Beratungsstellen f\xfcr vulnerable Gruppen, Organisationen, die in Volksgesundheit oder HIV-Pr\xe4vention arbeiten. Manche arbeiten speziell mit jungen Menschen mit psychischen Problemen.\n\nEs ist ein Bereich, der mentale Stabilit\xe4t verlangt. Du begegnest manchmal Krankheit, Alter und Tod. Die Aufnahmeorganisation bietet Supervision und Unterst\xfctzung, und du arbeitest nie allein in schweren Situationen. Aber es ist wichtig, ehrlich zu reflektieren, ob du die Ressourcen daf\xfcr hast.",examples:[{icon:"\uD83D\uDC75",title:"Altenpflege",desc:"Gesellschaft, Vorlesen, Spazierg\xe4nge, Gemeinschaftsaktivit\xe4ten in Pflegeheimen oder mit isolierten \xe4lteren Menschen."},{icon:"♿",title:"Behindertenhilfe",desc:"Assistiere in Tagesangeboten, begleite bei Ausfl\xfcgen, sei Schwimmkamerad oder Mitspieler bei Freizeitaktivit\xe4ten."},{icon:"\uD83D\uDD4A️",title:"Palliativversorgung & Hospiz",desc:"Sei eine stille Pr\xe4senz f\xfcr Menschen am Lebensende. Umfangreiche Supervision und Unterst\xfctzung enthalten."},{icon:"\uD83C\uDFE5",title:"Niedrigschwellige Beratung",desc:"Hilf in Beratungsstellen, die mit Obdachlosen, Suchtkranken oder Menschen ohne Papiere zu Gesundheitsfragen arbeiten."},{icon:"\uD83D\uDCE2",title:"Volksgesundheitsarbeit",desc:"Informiere \xfcber sexuelle Gesundheit, psychische Gesundheit, Sucht oder Impfungen — oft in Schulen oder bei Veranstaltungen."},{icon:"\uD83E\uDDE0",title:"Psychische Gesundheit Jugendlicher",desc:"Unterst\xfctze Organisationen, die mit jungen Menschen mit Angstst\xf6rungen, Depressionen oder sozialer Isolation arbeiten."}],skills:["Mentale Stabilit\xe4t","Empathie ohne zu absorbieren","Konkrete F\xfcrsorge","F\xe4higkeit, in Stille zu sitzen","Hygienebewusstsein","Diskretion","Ruhe unter Druck"],suitedFor:["Du, der/die \xfcber eine Zukunft in Gesundheitswesen, Sozialwesen, Psychologie oder Volksgesundheit nachdenkt.","Du, der/die mentale Stabilit\xe4t und Selbstreflexion hat.","Du, der/die keine Angst vor dem K\xf6rperlichen, Zerbrechlichen, Menschlichen hat.","Du, der/die dem Leben in seiner ganzen Breite begegnen will — einschlie\xdflich Alter und Abschied."],practical:{duration:"6–12 Monate. Manche Palliativprojekte verlangen mindestens 9 Monate, um Kontinuit\xe4t mit Pflegebed\xfcrftigen aufzubauen.",languages:"Die Landessprache ist oft essentiell — Beziehungen werden im Gespr\xe4ch aufgebaut. Englisch reicht selten weit in der t\xe4glichen Pflege.",requirements:"Mentale Stabilit\xe4t und Selbstreflexion sind wichtig. F\xfchrungszeugnis oft erforderlich. Erfahrung in der Pflege von Angeh\xf6rigen ist von Vorteil."}}}}}}]);